  ('elementary-8b44517b-moex-00248', 'elementary-8b44517b', 'elementary-8b44517b-moex-113-df89b7fb', 'sub-elementary-8b44517b-02', NULL, 'single_choice', '勞動部國際事務合作與交流、國際組織之參與及國際勞動議題諮商等業務事項，是由下列何一單位主掌？', '["勞動關係司", "綜合規劃司", "國際合作司", "國際組織司"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:30+00:00", "source_pdf_sha1": "664e5dd214da", "answer_pdf_sha1": "920fc8b6abca", "source_family": "moex-gov-tw", "moex": {"exam_code": "113010", "c": "503", "s": "0204", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "勞工行政與勞工法規大意", "year": "113", "exam_name": "113年公務人員初等考試", "original_question_number": 3, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "勞工行政"}'::jsonb, NULL),
  ('elementary-8b44517b-moex-00249', 'elementary-8b44517b', 'elementary-8b44517b-moex-113-df89b7fb', 'sub-elementary-8b44517b-02', NULL, 'single_choice', '勞動部管轄工資、工作時間、休息之業務是由下列何一單位主掌？', '["勞動條件及就業平等司", "勞動基準司", "勞動關係司", "勞動標準司"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:30+00:00", "source_pdf_sha1": "664e5dd214da", "answer_pdf_sha1": "920fc8b6abca", "source_family": "moex-gov-tw", "moex": {"exam_code": "113010", "c": "503", "s": "0204", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "勞工行政與勞工法規大意", "year": "113", "exam_name": "113年公務人員初等考試", "original_question_number": 4, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "勞工行政"}'::jsonb, NULL),
  ('elementary-8b44517b-moex-00250', 'elementary-8b44517b', 'elementary-8b44517b-moex-113-df89b7fb', 'sub-elementary-8b44517b-02', NULL, 'single_choice', '有關就業服務法規定雇主得聘僱外國留學生在我國從事工作，依就業服務法第50條第1項第1款規定， 下列敘述何者正確？', '["雇主聘僱就讀於公立或已立案私立大專校院之外國留學生從事工作，每星期最長為12小時", "雇主聘僱就讀於公立或已立案私立大專校院之外國留學生從事工作，其工作時間除寒暑假外，每星期最 長為20小時", "雇主聘僱就讀於公立或已立案私立大專校院之外國留學生從事工作，雇主可以為該外國留學生所就讀 之學校，從薪資中代扣學雜費", "雇主聘僱就讀於公立或已立案私立大專校院之外國留學生從事工作，可以低於基本工資而給薪"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:30+00:00", "source_pdf_sha1": "664e5dd214da", "answer_pdf_sha1": "920fc8b6abca", "source_family": "moex-gov-tw", "moex": {"exam_code": "113010", "c": "503", "s": "0204", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "勞工行政與勞工法規大意", "year": "113", "exam_name": "113年公務人員初等考試", "original_question_number": 5, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "勞工行政"}'::jsonb, NULL),
  ('elementary-8b44517b-moex-00251', 'elementary-8b44517b', 'elementary-8b44517b-moex-113-df89b7fb', 'sub-elementary-8b44517b-02', NULL, 'single_choice', '為維護身心障礙者之權益，身心障礙者權益保障法對身心障礙者之職業重建服務，下列敘述何者錯誤？', '["各級勞工主管機關應參考身心障礙者就業意願，由職業重建個案管理員評估身心障礙者能力與需求，而 訂定適切之個別化職業重建服務計畫", "身心障礙者職務再設計之職業重建服務，僅得由身心障礙者之監護人向各級社會行政主管機關提出申請", "對身心障礙者之職業重建服務，包括對其提供創業輔導", "各級勞工主管機關，對身心障礙者提供職業重建服務，於必要時得委託民間團體辦理"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:30+00:00", "source_pdf_sha1": "664e5dd214da", "answer_pdf_sha1": "920fc8b6abca", "source_family": "moex-gov-tw", "moex": {"exam_code": "113010", "c": "503", "s": "0204", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "勞工行政與勞工法規大意", "year": "113", "exam_name": "113年公務人員初等考試", "original_question_number": 6, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "勞工行政"}'::jsonb, NULL),
  ('elementary-8b44517b-moex-00252', 'elementary-8b44517b', 'elementary-8b44517b-moex-113-df89b7fb', 'sub-elementary-8b44517b-02', NULL, 'single_choice', '為提升職工福利，職工福利金條例規定設置職工福利委員會，下列敘述何者錯誤？', '["職工福利金條例規定職工福利委員會之工會代表，不得少於三分之二", "職工福利委員會之設置，應依職工福利金條例及職工福利委員會組織準則之規定而設置", "職工福利委員會委員之任期，每一任不得超過2年", "職工福利委員會委員均為無給職"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:30+00:00", "source_pdf_sha1": "664e5dd214da", "answer_pdf_sha1": "920fc8b6abca", "source_family": "moex-gov-tw", "moex": {"exam_code": "113010", "c": "503", "s": "0204", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "勞工行政與勞工法規大意", "year": "113", "exam_name": "113年公務人員初等考試", "original_question_number": 7, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "勞工行政"}'::jsonb, NULL),
  ('elementary-8b44517b-moex-00253', 'elementary-8b44517b', 'elementary-8b44517b-moex-113-df89b7fb', 'sub-elementary-8b44517b-02', NULL, 'single_choice', '依勞動基準法及其施行細則關於工作規則之規定，下列何者錯誤？', '["僱用30人以上之雇主，應依其事業性質，訂定工作規則", "雇主僱用勞工人數，係以同一雇主僱用適用勞動基準法之勞工人數計算，惟不包括分支機構之僱用人數", "工作規則的訂定，應於訂定日後之30日內報請當地主管機關核備", "主管機關認為有必要時，得通知雇主修訂其所報請核備之工作規則"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:30+00:00", "source_pdf_sha1": "664e5dd214da", "answer_pdf_sha1": "920fc8b6abca", "source_family": "moex-gov-tw", "moex": {"exam_code": "113010", "c": "503", "s": "0204", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "勞工行政與勞工法規大意", "year": "113", "exam_name": "113年公務人員初等考試", "original_question_number": 8, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "勞工行政"}'::jsonb, NULL),
  ('elementary-8b44517b-moex-00254', 'elementary-8b44517b', 'elementary-8b44517b-moex-113-df89b7fb', 'sub-elementary-8b44517b-02', NULL, 'single_choice', '根據勞動基準法，關於禁止強迫勞動之規定，下列敘述何者錯誤？', '["雇主不得以強暴、脅迫、拘禁或其他非法之方法，強制勞工從事勞動", "雇主不得變動勞工原有之工作職務", "雇主於違反禁止強迫勞動規定時，處5年以下有期徒刑、拘役或科或併科新臺幣75萬元以下罰金", "雇主以強迫勞動行為所建立之勞動契約，無效"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:30+00:00", "source_pdf_sha1": "664e5dd214da", "answer_pdf_sha1": "920fc8b6abca", "source_family": "moex-gov-tw", "moex": {"exam_code": "113010", "c": "503", "s": "0204", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "勞工行政與勞工法規大意", "year": "113", "exam_name": "113年公務人員初等考試", "original_question_number": 9, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "勞工行政"}'::jsonb, NULL),
  ('elementary-8b44517b-moex-00255', 'elementary-8b44517b', 'elementary-8b44517b-moex-113-df89b7fb', 'sub-elementary-8b44517b-02', NULL, 'single_choice', '下列那一項補償不是勞動基準法之職災補償？', '["醫療補償", "工資補償", "死亡補償", "失蹤補償"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:30+00:00", "source_pdf_sha1": "664e5dd214da", "answer_pdf_sha1": "920fc8b6abca", "source_family": "moex-gov-tw", "moex": {"exam_code": "113010", "c": "503", "s": "0204", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "勞工行政與勞工法規大意", "year": "113", "exam_name": "113年公務人員初等考試", "original_question_number": 10, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "勞工行政"}'::jsonb, NULL),
  ('elementary-8b44517b-moex-00256', 'elementary-8b44517b', 'elementary-8b44517b-moex-113-df89b7fb', 'sub-elementary-8b44517b-02', NULL, 'single_choice', '身心障礙者權益保障法之身心障礙者定額進用制度，下列敘述何者正確？', '["民營事業機構員工總人數50人以上者所僱用的身心障礙者人數，不得低於員工總人數1%，且不得少 於1人", "身心障礙者定額進用之義務單位，如有未足額進用身心障礙者，僅需繳納差額補助費，即不會有其他不 利益之處分", "私立學校、團體及民營事業機構等身心障礙者定額進用之義務單位，無正當理由如有未足額進用身心障 礙者，由勞動部勞動力發展署處以2萬元以上10萬元以下罰鍰", "雇主進用全時工作之身心障礙員工，若其月領薪資未達勞動基準法按月計酬之基本工資數額者，並不計 入該雇主進用身心障礙者人數及員工總人數之中"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:30+00:00", "source_pdf_sha1": "664e5dd214da", "answer_pdf_sha1": "920fc8b6abca", "source_family": "moex-gov-tw", "moex": {"exam_code": "113010", "c": "503", "s": "0204", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "勞工行政與勞工法規大意", "year": "113", "exam_name": "113年公務人員初等考試", "original_question_number": 11, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "勞工行政"}'::jsonb, NULL)
